import{_ as r,o as t,c as p,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"单兵轰炸单元 蝇王","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/4.综合类/地狱纳米辅助改造：奥西里斯/单兵轰炸单元 蝇王 .md","filePath":"4.资源分区/2.改造与功法/改造/4.综合类/地狱纳米辅助改造：奥西里斯/单兵轰炸单元 蝇王 .md"}'),o={name:"4.资源分区/2.改造与功法/改造/4.综合类/地狱纳米辅助改造：奥西里斯/单兵轰炸单元 蝇王 .md"};function _(d,a,l,i,b,c){return t(),p("div",null,[...a[0]||(a[0]=[e("h1",{id:"单兵轰炸单元-蝇王",tabindex:"-1"},[n("单兵轰炸单元 蝇王 "),e("a",{class:"header-anchor",href:"#单兵轰炸单元-蝇王","aria-label":'Permalink to "单兵轰炸单元 蝇王"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌032")])])],-1),s('<h1 id="单兵轰炸单元-蝇王-1" tabindex="-1">单兵轰炸单元 蝇王 <a class="header-anchor" href="#单兵轰炸单元-蝇王-1" aria-label="Permalink to &quot;单兵轰炸单元 蝇王&quot;">​</a></h1><p>单兵轰炸单元：蝇王<br> 【当文明的篝火熄灭，当理性的歌声沉默，古老的本能便会苏醒，在废墟之上加冕为王。它的嗡鸣，便是新时代的序曲，亦是旧世界的送葬。】</p><p>这并非简单的武器背包，而是一具沉重、狰狞的金属造物，如同某种蛮荒神祇的移动祭坛。黑铁色的外壳上布满了散热鳍片与能量导管，无数细小的红色指示灯在其表面明灭不定，仿佛无数觊觎的复眼。启动时，核心单元会发出低沉如巨虫振翅的嗡鸣，那是“蝇王”别西卜的低语，宣告着毁灭的降临。此装备占据双手及肩部，切换模式时，背包的结构会发生令人不安的机械重组。</p><p>1：副炮模式: 进入此戒备姿态需一个花招动作。背包两侧的辅助炮口缓缓展开，如同节肢动物试探性伸出的利爪。<br> 2: 全解放模式: 进入、切换或脱离此毁灭形态，都需要一个移动动作。背包主体变形，巨大的主炮口如深渊巨口般张开，内部闪烁着不祥的能量光芒。</p><p>C+1500<br> 【最初的献祭已备妥，饥饿的“神祇”开始显露它的獠牙。】</p><p>武器伤害13L<br> 射程150M<br> 武器类型：炮<br> 蝇王需要使用【操控+射击+炮+辅助专业：奥西里斯】进行射击攻击<br> 特性：【无限子弹】</p><p>效果1：副炮模式 - “群蝇的低语”<br> 以移动动作使用，更改这一武器下一次攻击模式，令背包两侧的炮口会喷射出密集的能量弹幕，这并非精准的狙杀，而是如同蜂群过境般的无差别覆盖。这一次攻击将命中以你为起始点，你面前120°扇形范围内的所有单位，目标以反射豁免。此次攻击中的射程增加一倍，额外获得【连射】特性，每一束能量都带着微弱的撕裂声，如同无数细小利齿的啃噬。</p><p>效果2：全解放模式 - “野兽的咆哮”<br> 标准动作使用，释放“蝇王”的真正力量，背包主体变形，主炮口凝聚起毁灭性的幽能。进行一次攻击，这次攻击将对目标点为圆心，半径为20米内的所有单位造成伤害。在此次攻击中，你在攻击检定上获得等同于你互动属性上的传奇属性之和x2点DP的增强加值。炮击过后，过载的能量核心需要至少3轮时间冷却，其间无法再次发动此模式的攻击，只有沉重的喘息声从背包中传出，仿佛巨兽在积蓄下一次的怒火。</p><p>B+3000<br> 【“蝇王”的权柄已然稳固，它的信徒们见证了真正的力量。现在，让一切归于虚无。】</p><p>武器伤害在上一级的基础上再+7L。<br> 背包的形态更加狰狞，表面的红色指示灯闪烁得更加急促，如同兴奋跳动的心脏。这把武器现在具有【8加骰】。</p><p>全解放模式 - “虚无的献祭”<br> 现在，以全解放模式发动的炮击，除了原有的毁灭性力量外，额外具有【湮灭】效果。被集束能量直接命中的区域，物质结构将发生不可逆的崩解，仿佛被投入了虚空的熔炉。并且，你在攻击检定上额外获得等同于你互动类属性传奇属性之和x1点附加成功。这是“蝇王”对其忠实仆从的最终赏赐——将一切秩序与存在彻底抹除的权力。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',13)])])}const m=r(o,[["render",_]]);export{f as __pageData,m as default};
